def status(cw, account_id, body, BOT_ACCOUNT_ID, AI_flag, AI_room_id, AI_second_id, AI_count, role, less_flag, less_room_id):
    cw.messagesend(f"""[info][title]状態確認[/title][code]account_id: {account_id}\nbody: {body}\nBOT_ID: {BOT_ACCOUNT_ID}\n一致?: {int(account_id) == BOT_ACCOUNT_ID}\nAI_flag: {AI_flag}\nAI_room_id: {AI_room_id}\nAI_second_id: {AI_second_id}\nAI_count: {AI_count}\nrole : {role}\n less-battle : {less_flag}\n less-room_id : {less_room_id}[/code][/info]""")